import{_ as a,o as t,c as o,a2 as r}from"./chunks/framework.D5wUhsuj.js";const h=JSON.parse('{"title":"Backup and Restore","description":"","frontmatter":{},"headers":[],"relativePath":"admin/backup_restore.md","filePath":"admin/backup_restore.md","lastUpdated":1783543014000}'),i={name:"admin/backup_restore.md"};function s(n,e,l,c,p,d){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="backup-and-restore" tabindex="-1">Backup and Restore <a class="header-anchor" href="#backup-and-restore" aria-label="Permalink to &quot;Backup and Restore&quot;">​</a></h1><p>prokube backups are operational disaster-recovery backups. They are not an upgrade mechanism and should be restored only into a compatible prokube deployment, normally the same platform version.</p><p>Backup setup is deployment-specific. Confirm the installed backup stack, storage location, schedule, and restore procedure for the target environment before relying on it.</p><h2 id="what-to-back-up" tabindex="-1">What to Back Up <a class="header-anchor" href="#what-to-back-up" aria-label="Permalink to &quot;What to Back Up&quot;">​</a></h2><p>A useful prokube backup covers both Kubernetes resources and application data. Kubernetes manifests alone are not enough because platform components store state in databases, object storage, and persistent volumes.</p><p>Typical backup scope includes:</p><ul><li>Keycloak configuration and database state;</li><li>Kubeflow Profiles, Notebook servers and volumes, Katib experiments, Pipelines metadata, and KServe resources;</li><li>MinIO tenant configuration and object data;</li><li>MLflow experiments, runs, artifacts, registered models, and permission state;</li><li>platform configuration that is not otherwise recoverable from GitOps.</li></ul><p>Some deployments use Velero plus application-specific backup steps. Others use provider-native snapshots and external database/object-storage backups. The important requirement is that restore has been tested end to end, including application data.</p><h2 id="backup-storage" tabindex="-1">Backup Storage <a class="header-anchor" href="#backup-storage" aria-label="Permalink to &quot;Backup Storage&quot;">​</a></h2><p>Store backups outside the prokube cluster. An S3-compatible bucket in a separate failure domain is a common target.</p><p>Backup storage should have:</p><ul><li>lifecycle and retention rules that match the recovery policy;</li><li>restricted write/delete permissions;</li><li>monitoring for failed uploads and unexpected growth;</li><li>protection from accidental deletion where supported by the provider.</li></ul><p>Backups that depend on Kubernetes volume snapshots require a CSI storage class and snapshot support. Without CSI snapshot support, notebook volumes and other persistent volumes may need a different backup method or may not be covered fully.</p><h2 id="scheduling-and-retention" tabindex="-1">Scheduling and Retention <a class="header-anchor" href="#scheduling-and-retention" aria-label="Permalink to &quot;Scheduling and Retention&quot;">​</a></h2><p>Most production deployments run scheduled backups and allow manual backups before maintenance. The schedule and retention period are environment decisions. Do not assume that a default backup schedule exists unless it is visible in the deployment configuration and recent backup jobs have succeeded.</p><p>Before major maintenance:</p><ol><li>Confirm the latest successful backup timestamp.</li><li>Trigger a manual backup if the last backup is too old for the planned change.</li><li>Confirm backup objects exist in external storage.</li><li>Confirm restore instructions for the installed platform version are available.</li></ol><h2 id="restore-expectations" tabindex="-1">Restore Expectations <a class="header-anchor" href="#restore-expectations" aria-label="Permalink to &quot;Restore Expectations&quot;">​</a></h2><p>Restores are manual operations. Plan a restore as a maintenance window, not a normal user workflow.</p><p>Before restoring:</p><ul><li>identify the exact prokube version and deployment configuration that produced the backup;</li><li>verify target cluster capacity, storage classes, DNS, TLS, and identity-provider configuration;</li><li>stop or isolate workloads that could write conflicting state;</li><li>restore Kubernetes resources and application data in the order required by the deployment;</li><li>validate login, workspaces, object storage, Labs, Pipelines, MLflow, and Model Serving after restore.</li></ul><p>Replication is not backup. Replicated storage can survive a node or disk failure, but it does not protect against accidental deletion, corrupted data, faulty migrations, or destructive admin commands.</p><h2 id="host-level-items" tabindex="-1">Host-Level Items <a class="header-anchor" href="#host-level-items" aria-label="Permalink to &quot;Host-Level Items&quot;">​</a></h2><p>For small self-managed deployments, also document and back up host-level configuration that is outside Kubernetes, such as SSH access policy, network configuration, firewall rules, DNS records, certificates, and cloud-provider credentials. Keep those backups in the same operational runbook as the platform restore procedure.</p><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./operations_runbooks.html">Operations Runbooks</a></li><li><a href="./storage.html">Storage</a></li><li><a href="./upgrading.html">Upgrading</a></li></ul>',26)])])}const m=a(i,[["render",s]]);export{h as __pageData,m as default};
